**Key Security Controls**:
- Centralized error handler that returns only generic messages to clients while logging detailed errors server-side with a correlation ID.
- Sensitive data protection: never log passwords, session tokens, or full request bodies; logs contain only minimal, non-secret identifiers.
- User enumeration prevention by using a single generic authentication error message and logging the real reason only on the server.

In production, you want consistent, structured logs, environment-aware error responses, secret redaction, and protections against log injection. You also need monitoring, rate limiting, and audit trails that don't expose sensitive data.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import { Pool } from 'pg';
import crypto from 'crypto';
import helmet from 'helmet';
import rateLimit from 'express-rate-limit';

const app = express();
const ENV = process.env.NODE_ENV || 'development';

app.use(express.json());
app.use(helmet());

// Basic rate limiting for auth endpoints
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 20,
  standardHeaders: true,
  legacyHeaders: false
});

const pool = new Pool({
  connectionString: process.env.DB_URL || 'postgres://user:pass@localhost/appdb',
  max: 10,
  idleTimeoutMillis: 30000
});

// Structured logger interface (can be wired to pino/winston etc.)
interface Logger {
  info(msg: string, meta?: Record<string, unknown>): void;
  warn(msg: string, meta?: Record<string, unknown>): void;
  error(msg: string, meta?: Record<string, unknown>): void;
}

const logger: Logger = {
  info: (msg, meta) => console.log(JSON.stringify({ level: 'info', msg, ...meta })),
  warn: (msg, meta) => console.warn(JSON.stringify({ level: 'warn', msg, ...meta })),
  error: (msg, meta) => console.error(JSON.stringify({ level: 'error', msg, ...meta }))
};

// Sanitize data for logs to avoid log injection and secret leakage
function sanitizeForLog(input: unknown): unknown {
  if (typeof input === 'string') {
    return input.replace(/[\r\n]/g, ' '); // strip newlines
  }
  if (typeof input === 'object' && input !== null) {
    const clone: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(input)) {
      if (/password|token|secret|cookie/i.test(key)) {
        clone[key] = '[REDACTED]';
      } else {
        clone[key] = sanitizeForLog(value);
      }
    }
    return clone;
  }
  return input;
}

function auditLog(action: string, meta: Record<string, unknown>): void {
  logger.info('audit', {
    action,
    ...sanitizeForLog(meta),
    ts: new Date().toISOString()
  });
}

function errorHandler(err: any, req: Request, res: Response, _next: NextFunction) {
  const correlationId = crypto.randomUUID();

  logger.error('unhandled_error', {
    id: correlationId,
    path: req.path,
    method: req.method,
    message: sanitizeForLog(err?.message),
    stack: ENV === 'development' ? sanitizeForLog(err?.stack) : undefined
  });

  const clientError: Record<string, unknown> = {
    error: 'Internal server error',
    id: correlationId
  };

  if (ENV === 'development') {
    clientError.detail = err?.message;
  }

  res.status(500).json(clientError);
}

app.post('/api/login', authLimiter, async (req: Request, res: Response, next: NextFunction) => {
  const { email, password } = req.body as { email?: string; password?: string };

  if (!email || !password) {
    return res.status(400).json({ error: 'Missing required fields' });
  }

  try {
    const result = await pool.query(
      'SELECT id, email, password_hash FROM users WHERE email = $1',
      [email]
    );

    const authError = 'Invalid email or password';

    if (result.rowCount === 0) {
      auditLog('login_failed_unknown_email', { email });
      return res.status(401).json({ error: authError });
    }

    const user = result.rows[0];

    // Placeholder: replace with proper password hash verification
    const isPasswordValid = user.password_hash === password;
    if (!isPasswordValid) {
      auditLog('login_failed_wrong_password', { userId: user.id });
      return res.status(401).json({ error: authError });
    }

    const sessionToken = crypto.randomBytes(32).toString('hex');

    // Do NOT log the token; log only non-sensitive identifiers
    auditLog('login_success', { userId: user.id, ip: req.ip });

    res.json({ token: sessionToken });
  } catch (err) {
    return next(err);
  }
});

// Health check without sensitive info
app.get('/health', (_req: Request, res: Response) => {
  res.json({ status: 'ok', env: ENV === 'production' ? 'prod' : ENV });
});

app.use(errorHandler);

const port = Number(process.env.PORT) || 3000;
app.listen(port, () => {
  logger.info('server_started', { port, env: ENV });
});
```

**Defense in Depth Layers**:
1. **Environment-aware error handling**:
   ```typescript
   const clientError: Record<string, unknown> = { error: 'Internal server error', id: correlationId };
   if (ENV === 'development') {
     clientError.detail = err?.message; // Extra detail only in dev
   }
   res.status(500).json(clientError);
   ```
   - Production hides internal details, development can show more for debugging.

2. **Sanitized, structured logging**:
   ```typescript
