```

**Why This Is Dangerous**:
- Any website can send authenticated requests to your API using the victim's cookies or tokens because `origin: '*'` plus `credentials: true` breaks the CORS trust model.
- Sensitive data (like email, roles, API keys) becomes readable by malicious JavaScript running in the victim's browser.
- Browsers rely on CORS to protect cross-origin reads; misconfiguration effectively bypasses Same-Origin Policy.

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import cors, { CorsOptions } from 'cors';

const app = express();
const PORT = 3000;

// In real apps, load from config / environment
const ALLOWED_ORIGINS: string[] = [
  'https://app.example.com',
  'https://admin.example.com',
];

const corsOptions: CorsOptions = {
  origin: (origin, callback) => {
    // Allow server-to-server or same-origin (no Origin header)
    if (!origin) {
      return callback(null, true);
    }

    if (ALLOWED_ORIGINS.includes(origin)) {
      return callback(null, true);
    }

    // Log and reject unknown origins
    console.warn(`[CORS] Blocked origin: ${origin}`);
    return callback(new Error('Not allowed by CORS'));
  },
  credentials: true, // Only safe because we strictly control origins
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization'],
};

app.use(express.json());

// Safe CORS configuration
app.use((req: Request, res: Response, next: NextFunction) => {
  cors(corsOptions)(req, res, (err: any) => {
    if (err) {
      console.error('[CORS] Error:', err.message);
      return res.status(403).json({ message: 'CORS policy violation' });
    }
    next();
  });
});

// Simple auth middleware placeholder
function requireAuth(req: Request, res: Response, next: NextFunction) {
  const auth = req.headers['authorization'];
  if (!auth) {
    return res.status(401).json({ message: 'Unauthorized' });
  }
  // In real app, verify token/session here
  next();
}

app.get('/api/user/profile', requireAuth, (req: Request, res: Response) => {
  // Return only necessary, non-secret data
  res.json({
    id: 123,
    email: 'user@example.com',
    role: 'user',
  });
});

// Centralized error handler to avoid leaking details
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('[Error]', err.message);
  res.status(500).json({ message: 'Internal server error' });
});

app.listen(PORT, () => {
  console.log(`Secure server running on http://localhost:${PORT}`);
});
```

**Key Security Controls**:
- **Restricted origin list**: Only known, trusted front-end domains are allowed via `ALLOWED_ORIGINS`, preventing arbitrary websites from sending authenticated cross-origin requests.
- **Error handling for CORS failures**: CORS errors are logged and return a generic 403 response, helping monitoring while not exposing internals.
- **Least-privilege data exposure & auth**: An auth middleware protects the route, and sensitive secrets (like API keys) are not returned, reducing impact even if misconfigurations occur.

In production, you should treat CORS as part of a broader access-control strategy: environment-specific configs, per-route CORS, separation of public vs. private APIs, and strong logging/monitoring.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import cors, { CorsOptionsDelegate } from 'cors';
import helmet from 'helmet';
import morgan from 'morgan';

const app = express();
const PORT = process.env.PORT ? parseInt(process.env.PORT, 10) : 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';

// Environment-specific allowed origins
const FRONTEND_ORIGINS: Record<string, string[]> = {
  development: ['http://localhost:4200', 'http://localhost:3001'],
  staging: ['https://staging.app.example.com'],
  production: ['https://app.example.com', 'https://admin.example.com'],
};

const MOBILE_APP_ORIGINS: Record<string, string[]> = {
  development: ['capacitor://localhost', 'ionic://localhost'],
  staging: ['https://staging-mobile.example.com'],
  production: ['https://mobile.example.com'],
};

const PUBLIC_ORIGINS: string[] = ['*']; // For truly public, read-only resources

const trustedOrigins = new Set<string>([
  ...(FRONTEND_ORIGINS[NODE_ENV] || []),
  ...(MOBILE_APP_ORIGINS[NODE_ENV] || []),
]);

// Dynamic CORS selector based on route type
const corsOptionsDelegate: CorsOptionsDelegate = (req, callback) => {
  const origin = req.header('Origin');

  // Public endpoints pattern: /public/*
  if (req.path.startsWith('/public/')) {
    // No credentials and wildcard allowed for read-only APIs
    return callback(null, {
      origin: PUBLIC_ORIGINS,
      credentials: false,
      methods: ['GET', 'OPTIONS'],
    });
  }

  // Protected API (authenticated)
  if (!origin) {
    // Allow same-origin / server-to-server
    return callback(null, { origin: false });
  }

  if (trustedOrigins.has(origin)) {
    return callback(null, {
      origin: origin,
      credentials: true,
      methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
      allowedHeaders: ['Content-Type', 'Authorization', 'X-Request-ID'],
      maxAge: 600,
    });
  }

  console.warn(`[CORS] Blocked origin in ${NODE_ENV}: ${origin} for ${req.path}`);
  return callback(new Error('Not allowed by CORS'));
};

// Security headers
app.use(
  helmet({
    contentSecurityPolicy: NODE_ENV === 'production' ? undefined : false,
  })
);

// Structured logging
app.use(morgan(NODE_ENV === 'production' ? 'combined' : 'dev'));

app.use(express.json());

// Central CORS handler with error handling
app.use((req: Request, res: Response, next: NextFunction) => {
  cors(corsOptionsDelegate)(req, res, (err: any) => {
    if (err) {
      console.error('[CORS] Error:', err.message, 'Path:', req.path);
      return res.status(403).json({ message: 'CORS policy violation' });
    }
    next();
  });
});

// Simple rate limiter stub (use a real library like express-rate-limit in prod)
const requestCounts: Record<string, number> = {};
function rateLimit(req: Request, res: Response, next: NextFunction) {
  const key = `${req.ip}:${req.path}`;
  requestCounts[key] = (requestCounts[key] || 0) + 1;
  if (requestCounts[key] > 100 && NODE_ENV === 'production') {
    console.warn(`[RateLimit] Too many requests from ${req.ip} to ${req.path}`);
    return res.status(429).json({ message: 'Too many requests' });
  }
  next();
}

// Auth middleware placeholder
function requireAuth(req: Request, res: Response, next: NextFunction) {
  const auth = req.header('Authorization');
  if (!auth) {
    return res.status(401).json({ message: 'Unauthorized' });
  }
  // Verify token/session here
  next();
}

// PUBLIC ENDPOINT (CORS: wildcard, no credentials)
app.get('/public/status', (req: Request, res: Response) => {
  res.json({
    status: 'ok',
    env: NODE_ENV,
    timestamp: new Date().toISOString(),
  });
});

// PROTECTED ENDPOINT (CORS: restricted, with credentials)
app.get('/api/user/profile', rateLimit, requireAuth, (req: Request, res: Response) => {
  res.json({ id: 123, email: 'user@example.com', role: 'user' });
});

// ADMIN-ONLY ENDPOINT with extra logging
app.post('/api/admin/rotate-keys', rateLimit, requireAuth, (req: Request, res: Response) => {
  console.info('[Audit] Key rotation requested', {
    ip: req.ip,
    path: req.path,
    time: new Date().toISOString(),
  });
  // Perform rotation
  res.status(202).json({ message: 'Key rotation started' });
});

// Global error handler
app.use((err: Error, req: Request, res: Response, _next: NextFunction) => {
  console.error('[Error]', {
    message: err.message,
    path: req.path,
    ip: req.ip,
  });
  res.status(500).json({ message: 'Internal server error' });
});

app.listen(PORT, () => {
  console.log(`API server (${NODE_ENV}) listening on port ${PORT}`);
});
```

**Defense in Depth Layers**:
1. **Environment-specific origin whitelists**:
   - Code example:
     ```typescript
     const FRONTEND_ORIGINS: Record<string, string[]> = { /* dev/staging/prod */ };
     const trustedOrigins = new Set<string>([/* env-specific */]);
     ```
   - Each environment has its own allowed origins to prevent dev or staging origins from accessing production APIs.

2. **Route-aware CORS configuration**:
   - Code example:
     ```typescript
     if (req.path.startsWith('/public/')) {
       return callback(null, { origin: PUBLIC_ORIGINS, credentials: false });
     }
     ```
   - Public endpoints use permissive but safe CORS (no credentials), while protected endpoints use strict origins and support credentials.

3. **Additional controls: auth, rate limiting, and security headers**:
   - Code examples:
     ```typescript
     app.use(helmet());           // Security headers
     app.use(rateLimit);          // Simple DoS/brute force mitigation
     app.use(requireAuth);        // Protects sensitive routes
     ```
   - Even if CORS is misconfigured, authentication, headers, and rate limiting reduce the blast radius and aid detection.

**Additional Protections**:
- **Monitoring & audit logging**: Use `morgan` plus structured logs for CORS denials, admin actions, and rate-limit events to feed into SIEM/alerting.
- **Graceful degradation**: Public status endpoints allow health checks without credentials, while failures in CORS or auth return controlled error messages (403/401/429) instead of crashing the app.
- **Configuration management**: Keep CORS origin lists and environment flags in configuration files or environment variables, not hard-coded, and ensure they are reviewed as part of deployment and security audits.
